B.Yq=new A.mk("Fachanwalt f\xfcr Arbeitsrecht","K\xfcndigung oder Aufhebungsvertrag pr\xfcfen und die Abfindung verhandeln.","Ein Fachanwalt f\xfcr Arbeitsrecht kann deine K\xfcndigung oder den Aufhebungsvertrag pr\xfcfen, die Erfolgsaussichten einer K\xfcndigungsschutzklage einsch\xe4tzen und die Abfindung verhandeln. Wichtig ist die Drei-Wochen-Frist des \xa7 4 KSchG: Nach Zugang einer schriftlichen K\xfcndigung bleibt nur diese Zeit, um Klage zu erheben.","Qualifizierte Kanzleien findest du \xfcber das amtliche Anwaltsverzeichnis der Bundesrechtsanwaltskammer oder die Rechtsanwaltskammer deines Bezirks. ExitKompass vermittelt keine Kanzleien und verdient nichts an diesem Hinweis.",B.abL,B.aXg)
B.Yr=new A.mk("Rechtsschutzversicherung pr\xfcfen","Bevor Beratungs- oder Prozesskosten entstehen.","Hast du eine Rechtsschutzversicherung mit Arbeitsrechtsschutz, \xfcbernimmt sie oft Anwalts- und Gerichtskosten. Pr\xfcfe die Wartezeit (meist drei Monate) und ob der Streitfall schon vor Vertragsbeginn angelegt war. Vor dem ersten Anwaltstermin lohnt sich eine Deckungsanfrage.","Steht in deiner Police oder erf\xe4hrst du direkt bei deiner Versicherung. ExitKompass empfiehlt keinen bestimmten Anbieter.",B.cc,B.nG)
B.aI9=s(["BerHG","\xa7\xa7 114 ff. ZPO"],t.s)
B.Yo=new A.mk("Beratungs- und Prozesskostenhilfe","Wenn anwaltliche Hilfe finanziell schwerf\xe4llt.","Mit geringem Einkommen kannst du beim \xf6rtlichen Amtsgericht einen Beratungshilfeschein f\xfcr eine Erstberatung beantragen (Eigenanteil rund 15 \u20ac). F\xfcr ein Gerichtsverfahren gibt es Prozesskostenhilfe. Beides beantragst du beim Amtsgericht deines Wohnorts.","Rechtsantragstelle des Amtsgerichts am Wohnort.",B.aI9,B.nG)
B.aMQ=s(["\xa7 38 SGB III","\xa7 141 SGB III"],t.s)
B.aRp={sperrzeit_eigenkuendigung:0,sperrzeit_wahrscheinlich:1,ruhen_158:2,alg_gedeckelt:3}
B.aXb=new A.fA(B.aRp,4,t.fF)
B.Yp=new A.mk("Agentur f\xfcr Arbeit: fr\xfch melden","Sobald du von der Beendigung erf\xe4hrst.","Melde dich sp\xe4testens drei Tage nach Kenntnis vom Ende arbeitsuchend \u2013 bei mehr als drei Monaten Vorlauf sp\xe4testens drei Monate vorher (\xa7 38 SGB III), sonst droht eine Minderung. Zum ersten Tag der Besch\xe4ftigungslosigkeit meldest du dich arbeitslos (\xa7 141 SGB III). Beides geht online oder pers\xf6nlich; die Agentur ber\xe4t auch zu ALG und Weiterbildung.","Agentur f\xfcr Arbeit \u2013 online oder in der \xf6rtlichen Dienststelle.",B.aMQ,B.aXb)
B.aLR=s(["\xa7 188 SGB V","\xa7 5 SGB V"],t.s)
B.aRr={kv_luecke:0}
B.aX8=new A.fA(B.aRr,1,t.fF)
B.Yn=new A.mk("Krankenversicherung kl\xe4ren","F\xfcr Monate ohne Gehalt und ohne ALG.","W\xe4hrend des ALG-Bezugs bist du in der Regel \xfcber die Agentur versichert. In L\xfcckenmonaten ohne Gehalt und ohne ALG musst du deinen Versicherungsschutz selbst sichern \u2013 etwa \xfcber die freiwillige Weiterversicherung oder die Familienversicherung. Melde dich fr\xfch bei deiner Krankenkasse; r\xfcckwirkende L\xfccken werden teuer. Privatversicherte haben eigene Regeln.","Deine gesetzliche Krankenkasse bzw. dein privater Versicherer.",B.aLR,B.aX8)
B.aJ8=s(["\xa7 102 BetrVG"],t.s)
B.Ym=new A.mk("Betriebsrat und Gewerkschaft","Wenn es einen Betriebsrat oder eine Gewerkschaft gibt.","Der Betriebsrat muss vor jeder K\xfcndigung angeh\xf6rt werden (\xa7 102 BetrVG) \u2013 eine unterbliebene Anh\xf6rung macht die K\xfcndigung unwirksam. Bist du Gewerkschaftsmitglied, geh\xf6ren arbeitsrechtliche Beratung und Rechtsschutz meist zum Mitgliedsbeitrag.","Betriebsrat im Unternehmen; deine Gewerkschaft.",B.aJ8,B.nG)
B.aKu=s([B.Yq,B.Yr,B.Yo,B.Yp,B.Yn,B.Ym],t.jQ)
